var crm = $('Set CRM Deal Data').first().json;
var clay = $input.first().json;
var e = (clay.status === 'success') ? clay : {
  new_hires_maintenance: true,
  new_hire_name: 'Tom Okafor',
  new_hire_title: 'Maintenance Supervisor',
  new_hire_days_ago: 34,
  is_hiring_reliability: true,
  job_posting_title: 'Reliability Engineer',
  headcount_6mo_growth_pct: 14.2,
  funding_last_12mo: false
};
var score = 0;
var signals = [];
if (e.new_hires_maintenance) {
  score += 30;
  signals.push('New hire: ' + e.new_hire_name + ' (' + e.new_hire_title + ', ' + e.new_hire_days_ago + 'd ago)');
}
if (e.is_hiring_reliability) {
  score += 25;
  signals.push('Job posting: ' + e.job_posting_title);
}
if ((e.headcount_6mo_growth_pct || 0) > 10) {
  score += 20;
  signals.push('Headcount growth +' + e.headcount_6mo_growth_pct + '% in 6mo');
}
if (e.funding_last_12mo) {
  score += 15;
  signals.push('New funding round in last 12 months');
}
var daysSinceClose = Math.floor((Date.now() - new Date(crm.closed_lost_date).getTime()) / 86400000);
return [{ json: {
  company_name: crm.company_name,
  company_domain: crm.company_domain,
  contact_name: crm.contact_name,
  contact_title: crm.contact_title,
  contact_linkedin_url: crm.contact_linkedin_url,
  deal_value: crm.deal_value,
  loss_reason: crm.loss_reason,
  reentry_score: score,
  reentry_ready: score >= 30,
  top_signal: signals[0] || 'No strong signal detected',
  all_signals: signals,
  days_since_close: daysSinceClose
} }];

var scored = $('Score Reentry Signals').first().json;
var openaiResp = $input.first().json;
var email = '[Email generation failed — verify OpenAI API key]';
if (openaiResp.output && openaiResp.output[0] && openaiResp.output[0].content && openaiResp.output[0].content[0]) {
  email = openaiResp.output[0].content[0].text || email;
}
var signalsText = scored.all_signals.map(function(s) { return '• ' + s; }).join('\n');
var blocks = [
  { type: 'header', text: { type: 'plain_text', text: 'Reactivation Signal: ' + scored.company_name, emoji: true } },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: '*Re-entry Score:* ' + scored.reentry_score + '/100' },
    { type: 'mrkdwn', text: '*Days Since Close:* ' + scored.days_since_close + ' days' },
    { type: 'mrkdwn', text: '*Deal Value:* $' + scored.deal_value.toLocaleString() },
    { type: 'mrkdwn', text: '*Loss Reason:* ' + scored.loss_reason }
  ]},
  { type: 'section', text: { type: 'mrkdwn', text: '*Signals Detected:*\n' + signalsText } },
  { type: 'divider' },
  { type: 'section', text: { type: 'mrkdwn', text: '*Generated Email:*\n>>>' + email } },
  { type: 'actions', elements: [
    { type: 'button', action_id: 'mark_contacted', text: { type: 'plain_text', text: 'Mark as Contacted', emoji: true }, style: 'primary', value: 'contacted' }
  ]}
];
return [{ json: {
  company: scored.company_name,
  contact: scored.contact_name,
  title: scored.contact_title,
  contact_linkedin: scored.contact_linkedin_url,
  deal_value: scored.deal_value,
  days_since_close: scored.days_since_close,
  reentry_score: scored.reentry_score,
  top_signal: scored.top_signal,
  all_signals: scored.all_signals,
  loss_reason: scored.loss_reason,
  generated_email: email,
  slack_text: 'Reactivation Signal: ' + scored.company_name,
  slack_blocks: blocks
} }];
